import React, { useState } from 'react';

const Login = ({ onLogin }) => {
  const [id, setId] = useState('');
  const [pass, setPass] = useState('');

  const handleEntry = (e) => {
    e.preventDefault();
    // Validación directa para Agus_rtn
    if (id === "Agus_rtn" && pass === "Maragus2417") {
      onLogin({ username: "Agus_rtn", role: "admin" });
    } else {
      alert("Acceso denegado a RTN MUSIC");
    }
  };

  return (
    <div className="h-screen bg-[#080808] flex items-center justify-center font-sans">
      <form onSubmit={handleEntry} className="bg-white/5 p-12 rounded-[48px] border border-white/10 w-full max-w-md backdrop-blur-xl">
        <div className="text-center mb-10">
          <h1 className="text-3xl font-black italic">RTN <span className="text-yellow-400">LOGIN</span></h1>
        </div>
        <input 
          type="text" placeholder="RTN ID" 
          className="w-full bg-black border border-white/10 p-4 rounded-2xl mb-4 text-white focus:border-yellow-400 outline-none"
          onChange={(e) => setId(e.target.value)}
        />
        <input 
          type="password" placeholder="PASSWORD" 
          className="w-full bg-black border border-white/10 p-4 rounded-2xl mb-8 text-white focus:border-yellow-400 outline-none"
          onChange={(e) => setPass(e.target.value)}
        />
        <button className="w-full bg-yellow-400 text-black font-black py-4 rounded-2xl hover:shadow-[0_0_30px_rgba(250,204,21,0.3)] transition-all">
          ENTRAR A LA CREW
        </button>
      </form>
    </div>
  );
};

export default Login;
